const triggerData = $('Execute Workflow Trigger').item.json;
const convState = $('Get Conv State').item.json;
const userRow = $('Upsert User').item.json;

const inputValue = (triggerData.text || '').trim().toLowerCase();

const step = convState.step;
let context = {};
try { context = typeof convState.context === 'string' ? JSON.parse(convState.context) : (convState.context || {}); } catch(e) { context = {}; }

const stepMap = {
  ask_name:     { key: 'name',           next: 'ask_age' },
  ask_age:      { key: 'age',            next: 'ask_gender', fn: v => parseInt(v) || 25 },
  ask_gender:   { key: 'gender',         next: 'ask_height' },
  ask_height:   { key: 'height_cm',      next: 'ask_weight', fn: v => parseFloat(v) || 170 },
  ask_weight:   { key: 'weight_kg',      next: 'ask_activity', fn: v => parseFloat(v) || 70 },
  ask_activity: { key: 'activity_level', next: 'ask_goal' },
  ask_goal:     { key: 'goal',           next: 'complete' }
};

const cur = stepMap[step];
if (cur) {
  context[cur.key] = cur.fn ? cur.fn(inputValue) : inputValue;
}

let dailyCalorieTarget = null;
if (context.weight_kg && context.height_cm && context.age && context.gender && context.activity_level && context.goal) {
  const isMale = context.gender === 'male';
  let bmr = isMale
    ? 10*context.weight_kg + 6.25*context.height_cm - 5*context.age + 5
    : 10*context.weight_kg + 6.25*context.height_cm - 5*context.age - 161;
  const mult = {sedentary:1.2,light:1.375,moderate:1.55,active:1.725,very_active:1.9};
  const tdee = bmr * (mult[context.activity_level] || 1.2);
  const offset = {toning:-400,mass:300,maintenance:0};
  dailyCalorieTarget = Math.round(tdee + (offset[context.goal] || 0));
  context.daily_calorie_target = dailyCalorieTarget;
}

const nextStep = cur ? cur.next : step;

return [{ json: {
  userId: userRow.id,
  telegramId: triggerData.telegramId,
  nextStep,
  context,
  dailyCalorieTarget,
  isComplete: nextStep === 'complete'
} }];
